import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getStarkNetIntelligence(walletAddress) {
  const [balances, txns] = await Promise.all([
    client.BalanceService.getTokenBalancesForWalletAddress("starknet-mainnet", walletAddress),
    client.TransactionService.getTransactionsForAddressV3("starknet-mainnet", walletAddress),
  ]);
  return { balances: balances.data?.items, txns: txns.data?.items };
}
